	private static int resolveSketchK(int kProp, int kCfg, int buckets, int kMult) {
		if (kProp > 0) {
			return kProp;
		}
		if (kCfg > 0) {
			return kCfg;
		}
		if (kMult > 0) {
			return Math.max(1, buckets * kMult);
		}
		return DEFAULT_SKETCH_NOMINAL_ENTRIES;
	}

